import React, { useEffect } from 'react';
import { createPortal } from 'react-dom';
import './Common.css';

function Modal({
  open = false,
  onClose,
  title = '',
  description = '',
  children,
  footer = null,
  size = 'md',
  closeOnOverlay = true,
  closeOnEsc = true,
  showCloseButton = true,
  className = '',
}) {
  useEffect(() => {
    if (!open) return undefined;

    const originalOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';

    return () => {
      document.body.style.overflow = originalOverflow;
    };
  }, [open]);

  useEffect(() => {
    if (!open || !closeOnEsc) return undefined;

    const handleKeyDown = (event) => {
      if (event.key === 'Escape') {
        onClose?.();
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [open, closeOnEsc, onClose]);

  if (!open || typeof document === 'undefined') return null;

  const handleOverlayClick = (event) => {
    if (!closeOnOverlay) return;
    if (event.target === event.currentTarget) {
      onClose?.();
    }
  };

  return createPortal(
    <div
      className="common-modal-backdrop"
      onMouseDown={handleOverlayClick}
      role="presentation"
    >
      <div
        className={[
          'common-modal',
          `common-modal--${size}`,
          className,
        ]
          .filter(Boolean)
          .join(' ')}
        role="dialog"
        aria-modal="true"
        aria-labelledby={title ? 'common-modal-title' : undefined}
        aria-describedby={description ? 'common-modal-description' : undefined}
      >
        <div className="common-modal__glow common-modal__glow--one" />
        <div className="common-modal__glow common-modal__glow--two" />

        {(title || description || showCloseButton) && (
          <div className="common-modal__header">
            <div className="common-modal__heading">
              {title ? (
                <h2 id="common-modal-title" className="common-modal__title">
                  {title}
                </h2>
              ) : null}

              {description ? (
                <p
                  id="common-modal-description"
                  className="common-modal__description"
                >
                  {description}
                </p>
              ) : null}
            </div>

            {showCloseButton ? (
              <button
                type="button"
                className="common-modal__close"
                onClick={() => onClose?.()}
                aria-label="모달 닫기"
              >
                <span />
                <span />
              </button>
            ) : null}
          </div>
        )}

        <div className="common-modal__body">{children}</div>

        {footer ? <div className="common-modal__footer">{footer}</div> : null}
      </div>
    </div>,
    document.body
  );
}

export default Modal;
